import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Careers = () => {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedJob, setSelectedJob] = useState(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [formData, setFormData] = useState({ name: '', email: '', resume: null });

  useEffect(() => {
    const fetchJobs = async () => {
      try {
        const res = await axios.get('http://localhost:5001/api/jobs');
        setJobs(res.data);
        setLoading(false);
      } catch (err) {
        console.error("Backend connection failed", err);
        setLoading(false);
      }
    };
    fetchJobs();
  }, []);

  return (
    <div className="bg-white font-sans min-h-screen">
      {/* HEADER */}
      <section className="pt-32 pb-16 px-6 text-center">
        <h2 className="text-6xl font-black text-gray-950 tracking-tighter mb-4">Join Our Team</h2>
        <p className="text-gray-500 font-bold uppercase tracking-widest text-sm">Explore open opportunities at Hudson</p>
      </section>

      {/* JOBS BOARD */}
      <section className="py-12 px-6 max-w-7xl mx-auto">

        {/* Table Header (Hidden on Mobile) */}
        <div className="hidden md:grid grid-cols-12 px-10 mb-6 text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">
          <div className="col-span-5">Job Title & Type</div>
          <div className="col-span-4">Location & Salary</div>
          <div className="col-span-3 text-right">Action</div>
        </div>

        <div className="grid gap-4">
          {loading ? (
            <div className="py-20 text-center animate-pulse">
               <p className="text-xl font-black text-gray-300 uppercase tracking-widest">Fetching Jobs...</p>
            </div>
          ) : jobs.length > 0 ? (
            jobs.map((job) => (
              <div key={job._id} className="group grid grid-cols-1 md:grid-cols-12 items-center p-8 md:p-10 bg-white border border-gray-100 rounded-[2.5rem] hover:shadow-2xl hover:border-orange-100 transition-all duration-500">

                {/* Column 1: Title & Type */}
                <div className="md:col-span-5">
                  <span className="inline-block px-3 py-1 bg-orange-50 text-orange-600 rounded-full text-[10px] font-black uppercase tracking-widest mb-3">
                    {job.type || 'On-site'}
                  </span>
                  <h3 className="text-2xl md:text-3xl font-black text-gray-950 group-hover:text-orange-600 transition-colors">
                    {job.title}
                  </h3>
                </div>

                {/* Column 2: Location & Salary */}
                <div className="md:col-span-4 mt-4 md:mt-0">
                  <div className="flex flex-col gap-1">
                    <p className="text-gray-950 font-black text-lg flex items-center gap-2">
                      <span className="text-orange-500 text-sm">📍</span> {job.loc}
                    </p>
                    <p className="text-gray-400 font-bold text-sm uppercase tracking-wider">
                      {job.salary || 'Competitive Pay'}
                    </p>
                  </div>
                </div>

                {/* Column 3: Action */}
                <div className="md:col-span-3 mt-6 md:mt-0 text-right">
                  <button 
                    onClick={() => { setSelectedJob(job); setIsFormOpen(true); }}
                    className="w-full md:w-auto bg-gray-950 text-white px-10 py-4 rounded-2xl font-black hover:bg-orange-600 hover:scale-105 active:scale-95 transition-all shadow-lg shadow-gray-200"
                  >
                    Apply Now
                  </button>
                </div>

              </div>
            ))
          ) : (
            <div className="py-20 text-center bg-gray-50 rounded-[3rem] border-2 border-dashed border-gray-200">
              <p className="text-gray-400 font-black uppercase tracking-widest">No active openings at the moment.</p>
            </div>
          )}
        </div>
      </section>

      {/* Modal logic aapki purani same rahegi... */}
    </div>
  );
};

export default Careers;
